from typing import Protocol


class LengthUnit(Protocol):
    name: str

    def to_meter(self, value: float) -> float: ...


class MeterUnit:
    name = "meter"

    def to_meter(self, value: float) -> float:
        return value


class FeetUnit:
    name = "feet"

    def to_meter(self, value: float) -> float:
        return value / 3.28084


class YardUnit:
    name = "yard"

    def to_meter(self, value: float) -> float:
        return value / 1.09361

from entity.length_unit import FeetUnit, LengthUnit, MeterUnit, YardUnit


class UnitRegistry:
    def __init__(self) -> None:
        self._units: dict[str, LengthUnit] = {}
        for unit in (MeterUnit(), FeetUnit(), YardUnit()):
            self.register(unit)

    def register(self, unit: LengthUnit) -> None:
        self._units[unit.name] = unit

    def get(self, name: str) -> LengthUnit:
        return self._units[name]

    def all_units(self) -> list[LengthUnit]:
        return list(self._units.values())

from entity.length_unit import LengthUnit
from entity.unit_registry import UnitRegistry


class Converter:
    def __init__(self, registry: UnitRegistry) -> None:
        self._registry = registry

    def convert(self, source_name: str, value: float) -> dict[str, float]:
        source = self._registry.get(source_name)
        meter_value = source.to_meter(value)
        return {
            unit.name: _from_meter(unit, meter_value)
            for unit in self._registry.all_units()
            if unit.name != source_name
        }


def _from_meter(unit: LengthUnit, meter_value: float) -> float:
    return meter_value / unit.to_meter(1.0)

